param([Parameter(Mandatory=$true)][string]$RunId,[int]$TimeoutSeconds=900)
$ErrorActionPreference='Stop';$root="$env:USERPROFILE\NoraMt5Harness";$run="$root\runs\$RunId";New-Item -ItemType Directory -Force $run|Out-Null
$mt='C:\Program Files\Darwinex MetaTrader 5';$term="$mt\terminal64.exe";$seed="$mt\backtest_run.ini";if(!(Test-Path $term) -or !(Test-Path $seed)){throw 'known MT5 terminal/config absent'}
$state=[ordered]@{run_id=$RunId;status='starting';started_utc=(Get-Date).ToUniversalTime().ToString('o');terminal=$term;build=(Get-Item $term).VersionInfo.FileVersion};function S{$state|ConvertTo-Json|Set-Content "$run\status.json" -Encoding utf8};S
try { $data=Get-ChildItem "$env:APPDATA\MetaQuotes\Terminal" -Directory|?{Test-Path "$($_.FullName)\origin.txt"}|select -First 1 -Expand FullName;$name="NoraMt5Harness_$RunId.htm";$source=Join-Path $data $name;$config=Get-Content $seed -Raw; $config=[regex]::Replace($config,'(?m)^Report=.*$',"Report=$name");$config=[regex]::Replace($config,'(?m)^ReplaceReport=.*$','ReplaceReport=1');$config=[regex]::Replace($config,'(?m)^ShutdownTerminal=.*$','ShutdownTerminal=1');Set-Content "$run\tester.ini" $config -Encoding ascii
 $expert=([regex]::Match($config,'(?m)^Expert=(.+)$')).Groups[1].Value;$ea=Join-Path $data ('MQL5\Experts\'+$expert+'.ex5');if(!(Test-Path $ea)){throw 'pinned EA absent'};$state.ea_sha256=(Get-FileHash $ea -Algorithm SHA256).Hash;$state.config_sha256=(Get-FileHash "$run\tester.ini" -Algorithm SHA256).Hash;$state.status='running';S
 $p=Start-Process $term -ArgumentList ('/config:"'+$run+'\tester.ini"') -PassThru;if(!$p.WaitForExit($TimeoutSeconds*1000)){Stop-Process $p -Force;throw 'timeout'};$state.exit_code=$p.ExitCode;if(!(Test-Path $source)){throw 'report absent'};Copy-Item $source "$run\report.htm" -Force;$state.status='completed';$state.completed_utc=(Get-Date).ToUniversalTime().ToString('o');S }
catch {$state.status='failed';$state.error=$_.Exception.Message;$state.completed_utc=(Get-Date).ToUniversalTime().ToString('o');S;throw}
